  ?msgFlow tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_daf7f0c4_1180_4eb5_932a_2b7c50230014> .
  OPTIONAL { ?msgFlow bboExt:sourceRef ?sourceRef . }
