  OPTIONAL { ?msgFlow bbo:name ?msgName . }
  OPTIONAL { ?msgFlow bboExt:messageRef ?messageRef . }

  # Find source and target participant names
  OPTIONAL {
    ?sourcePart a bboExt:Participant .
    FILTER(STRENDS(STR(?sourcePart), ?sourceRef))
    ?sourcePart bbo:name ?sourcePartName .
  }
  OPTIONAL {
    ?targetPart a bboExt:Participant .
    FILTER(STRENDS(STR(?targetPart), ?targetRef))
    ?targetPart bbo:name ?targetPartName .
  }

  FILTER(?sourceRef = "sid-FDA86F6F-8E7D-4792-B1D2-FFACAED6E3F6" || ?targetRef = "sid-FDA86F6F-8E7D-4792-B1D2-FFACAED6E3F6")
